/**
 * PROTO-220: Artifact Generation Protocol (AGP)
 * Autonomous artifact production with phi-encoded quality metrics.
 * 
 * Artifacts are outputs generated by the organism: code, documents,
 * analyses, decisions, etc. Each artifact is versioned and validated.
 */

const PHI = 1.618033988749895;
const HEARTBEAT = 873;

const ARTIFACT_TYPES = ['code', 'document', 'analysis', 'decision', 'model', 'data', 'config'];

class ArtifactGenerationProtocol {
  constructor() {
    this.artifacts = new Map();
    this.generators = new Map();
    this.validations = [];
    this.totalGenerated = 0;
    this.totalValidated = 0;
  }

  registerGenerator(id, config) {
    this.generators.set(id, {
      id,
      name: config.name || id,
      type: config.type || 'data',
      generateFn: config.generateFn,
      validateFn: config.validateFn,
      transforms: config.transforms || [],
      generationCount: 0,
      lastGenerated: null,
    });
    return id;
  }

  async generate(generatorId, input = {}) {
    const generator = this.generators.get(generatorId);
    if (!generator) {
      throw new Error(`Generator not found: ${generatorId}`);
    }
    
    const startTime = Date.now();
    
    try {
      // Generate artifact
      let content = generator.generateFn 
        ? await generator.generateFn(input)
        : input;
      
      // Apply transforms
      for (const transform of generator.transforms) {
        content = await transform(content);
      }
      
      const artifact = {
        id: `artifact-${Date.now()}-${Math.random().toString(36).slice(2)}`,
        generatorId,
        type: generator.type,
        content,
        input,
        version: 1,
        createdAt: Date.now(),
        generationTimeMs: Date.now() - startTime,
        validated: false,
        validationScore: null,
        phiQuality: this.calculatePhiQuality(content),
      };
      
      this.artifacts.set(artifact.id, artifact);
      generator.generationCount++;
      generator.lastGenerated = Date.now();
      this.totalGenerated++;
      
      return artifact;
    } catch (error) {
      return { error: error.message, generatorId, input };
    }
  }

  calculatePhiQuality(content) {
    // Phi-based quality metric
    let score = 0.5;  // Base score
    
    if (typeof content === 'string') {
      // Length-based quality (prefer phi-proportioned lengths)
      const len = content.length;
      const phiLen = Math.round(len / PHI);
      const deviation = Math.abs(len - phiLen * PHI) / len;
      score += (1 - deviation) * 0.3;
      
      // Complexity estimate
      const uniqueChars = new Set(content).size;
      const complexity = uniqueChars / content.length;
      score += complexity * PHI * 0.2;
    } else if (typeof content === 'object') {
      // Object structure quality
      const keys = Object.keys(content);
      const depth = this.objectDepth(content);
      score += Math.min(1, keys.length / 10) * 0.3;
      score += Math.min(1, depth / 5) * 0.2;
    }
    
    return Math.min(1, score);
  }

  objectDepth(obj, depth = 0) {
    if (typeof obj !== 'object' || obj === null) return depth;
    let maxDepth = depth;
    for (const value of Object.values(obj)) {
      maxDepth = Math.max(maxDepth, this.objectDepth(value, depth + 1));
    }
    return maxDepth;
  }

  async validate(artifactId) {
    const artifact = this.artifacts.get(artifactId);
    if (!artifact) return { valid: false, reason: 'Artifact not found' };
    
    const generator = this.generators.get(artifact.generatorId);
    let score = artifact.phiQuality;
    let valid = score > (PHI - 1);  // 0.618 threshold
    let details = [];
    
    // Run custom validation if available
    if (generator?.validateFn) {
      try {
        const customResult = await generator.validateFn(artifact.content);
        if (typeof customResult === 'number') {
          score = (score + customResult) / 2;
        } else if (customResult.score !== undefined) {
          score = (score + customResult.score) / 2;
          details = customResult.details || [];
        }
        valid = score > (PHI - 1);
      } catch (error) {
        details.push({ type: 'error', message: error.message });
        valid = false;
      }
    }
    
    artifact.validated = true;
    artifact.validationScore = score;
    artifact.validatedAt = Date.now();
    
    const validation = {
      artifactId,
      valid,
      score,
      threshold: PHI - 1,
      details,
      timestamp: Date.now(),
    };
    
    this.validations.push(validation);
    if (this.validations.length > 100) this.validations.shift();
    this.totalValidated++;
    
    return validation;
  }

  getArtifact(id) {
    return this.artifacts.get(id);
  }

  getArtifactsByType(type) {
    const results = [];
    for (const artifact of this.artifacts.values()) {
      if (artifact.type === type) {
        results.push(artifact);
      }
    }
    return results.sort((a, b) => b.createdAt - a.createdAt);
  }

  getRecentArtifacts(limit = 20) {
    return [...this.artifacts.values()]
      .sort((a, b) => b.createdAt - a.createdAt)
      .slice(0, limit);
  }

  getMetrics() {
    const byType = {};
    for (const type of ARTIFACT_TYPES) {
      byType[type] = 0;
    }
    
    let totalQuality = 0;
    for (const artifact of this.artifacts.values()) {
      byType[artifact.type] = (byType[artifact.type] || 0) + 1;
      totalQuality += artifact.phiQuality;
    }
    
    return {
      totalGenerated: this.totalGenerated,
      totalValidated: this.totalValidated,
      artifactCount: this.artifacts.size,
      generatorCount: this.generators.size,
      byType,
      avgPhiQuality: this.artifacts.size > 0 ? totalQuality / this.artifacts.size : 0,
      recentValidations: this.validations.slice(-10),
      artifactTypes: ARTIFACT_TYPES,
      qualityThreshold: PHI - 1,
      phi: PHI,
      heartbeat: HEARTBEAT,
    };
  }
}

export { ArtifactGenerationProtocol, ARTIFACT_TYPES };
export default ArtifactGenerationProtocol;
